const winston = require("winston");
require("winston-daily-rotate-file");
const path = require("path");

/**
 * Create a customizable logger.
 * @param {string} appName - The name of the application.
 * @param {string} logPath - The path where logs should be stored (optional, default is the root folder of the project).
 * @param {string} logLevel - The log level (optional, default is "info").
 * @returns {winston.Logger} A configured logger instance.
 */
const createLogger = (appName = "ApplicationName", logPath = "", logLevel = "info") => {
    // Define the log directory path
    const logDir = path.resolve(process.cwd(), logPath);

    // Define log format with metadata
    const logFormat = winston.format.combine(
        winston.format.metadata(), // Add metadata to log entries
        winston.format.json(), // Log in JSON format
        winston.format.timestamp({ format: "DD-MM-YYYY HH:mm:ss" }),
        winston.format.printf(info => {
            // Extract metadata from log entries
            const { timestamp, level, message, metadata } = info;
            let log = `${timestamp} [${level.toUpperCase()}]: ${message}`;
            // Add metadata to log message
            if (metadata) {
                log += `\n${JSON.stringify(metadata, null, 2)}`;
            }
            return log;
        })
    );

    // Create a logger that logs to both a file and the console
    return winston.createLogger({
        level: logLevel,
        format: logFormat,
        transports: [
            new winston.transports.Console(),
            new winston.transports.DailyRotateFile({
                format: logFormat,
                filename: path.join(logDir, `${appName}-%DATE%.log`),
                datePattern: "YYYY-MM-DD",
                zippedArchive: true,
                maxSize: "20m",
                maxFiles: "14d",
            }),
        ],
        exceptionHandlers: [
            new winston.transports.Console(),
            new winston.transports.DailyRotateFile({
                filename: path.join(logDir, `${appName}-exceptions-%DATE%.log`),
                datePattern: "YYYY-MM-DD",
                zippedArchive: true,
                maxSize: "20m",
                maxFiles: "14d",
            }),
        ],
    });
};

module.exports = createLogger;

