const winston = require("winston");
require("winston-daily-rotate-file");
const path = require("path");

/**
 * Create a customizable logger.
 * @param {string} appName - The name of the application.
 * @param {string} [logPath=""] - The path where logs should be stored (optional, default is the root folder of the project).
 * @param {string} [logLevel="info"] - The log level (optional, default is "info").
 * @returns {winston.Logger} A configured logger instance.
 */
const createLogger = (appName = "ApplicationName", logPath = "", logLevel = "info") => {
    // Resolve the log directory path relative to the current working directory
    const logDir = path.resolve(process.cwd(), logPath);

    // Define log format
    const logFormat = winston.format.combine(
        winston.format.metadata(), // Add metadata to log entries
        winston.format.timestamp({ format: "YYYY-MM-DDTHH:mm:ssZ" }), // ISO 8601 timestamp format
        winston.format.printf(info => {
            const { timestamp, level, message, metadata } = info;
            let log = `${timestamp} [${level.toUpperCase()}]: ${message}`;
            if (metadata) {
                log += `\n${JSON.stringify(metadata, null, 2)}`;
            }
            return log;
        })
    );

    // Determine if colorization should be applied based on environment
    const isDevelopment = process.env.NODE_ENV === 'development';
    const consoleFormat = isDevelopment ?
        winston.format.combine(winston.format.colorize(), logFormat) :
        logFormat;

    // Create transports
    const transports = [
        new winston.transports.Console({ format: consoleFormat }),
        new winston.transports.DailyRotateFile({
            format: logFormat,
            filename: path.join(logDir, `${appName}-%DATE%.log`),
            datePattern: "YYYY-MM-DD",
            zippedArchive: true,
            maxSize: "20m",
            maxFiles: "14d",
        }),
    ];

    // Exception handling
    transports.forEach(transport => {
        if (transport.handleExceptions) {
            transport.handleExceptions = true;
            transport.exitOnError = false;
        }
    });

    // Create a logger
    const logger = winston.createLogger({
        level: logLevel,
        format: logFormat,
        transports: transports,
    });

    // Handle unhandled promise rejections
    process.on('unhandledRejection', (reason, promise) => {
        logger.error('Unhandled Rejection at:', promise, 'reason:', reason);
    });

    // Return the configured logger instance
    return logger;
};

module.exports = createLogger;

